// Serve files through a controlled endpoint (not directly from filesystem)
app.get('/api/files/:fileId', authenticateUser, (req, res) => {
  const fileId = req.params.fileId;

  // Sanitize fileId to prevent path traversal
  if (!fileId || /[^a-zA-Z0-9_\-]/.test(fileId)) {
    return res.status(400).json({ error: 'Invalid file ID.' });
  }

  // Find the file in the upload directory
  const files = fs.readdirSync(UPLOAD_DIR);
  const matchingFile = files.find(f => f.startsWith(fileId) || path.basename(f, path.extname(f)) === fileId);

  if (!matchingFile) {
    return res.status(404).json({ error: 'File not found.' });
  }

  const filePath = path.join(UPLOAD_DIR, matchingFile);

  // Ensure the resolved path is within the upload directory
  const resolvedPath = path.resolve(filePath);
  if (!resolvedPath.startsWith(path.resolve(UPLOAD_DIR))) {
    return res.status(403).json({ error: 'Access denied.' });
  }

  // Set appropriate content disposition and type
  const ext = path.extname(matchingFile).toLowerCase();
  const mimeMap = {
    '.jpg': 'image/jpeg',
    '.jpeg': 'image/jpeg',
    '.png': 'image/png',
    '.gif': 'image/gif',
    '.svg': 'image/svg+xml',
    '.pdf': 'application/pdf',
    '.doc': 'application/msword',
    '.docx': 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
    '.zip': 'application/zip',
  };

  const contentType = mimeMap[ext] || 'application/octet-stream';

  // SVG files should be served with Content-Security-Policy to prevent XSS
  if (ext === '.svg') {
    res.setHeader('Content-Security-Policy', "default-src 'none'; style-src 'unsafe-inline'");
    res.setHeader('X-Content-Type-Options', 'nosniff');
  }

  res.setHeader('Content-Type', contentType);
  res.setHeader('Content-Disposition', `inline; filename="${matchingFile}"`);
  res.setHeader('X-Content-Type-Options', 'nosniff');

  res.sendFile(resolvedPath);
});

// Serve thumbnails through a controlled endpoint
app.get('/api/thumbnails/:fileId', authenticateUser, (req, res) => {
  const fileId = req.params.fileId;

  if (!fileId || /[^a-zA-Z0-9_\-]/.test(fileId)) {
    return res.status(400).json({ error: 'Invalid file ID.' });
  }

  const files = fs.readdirSync(THUMBNAIL_DIR);
  const matchingFile = files.find(f => f.includes(fileId));

  if (!matchingFile) {
    return res.status(404).json({ error: 'Thumbnail not found.' });
  }

  const filePath = path.join(THUMBNAIL_DIR, matchingFile);
  const resolvedPath = path.resolve(filePath);

  if (!resolvedPath.startsWith(path.resolve(THUMBNAIL_DIR))) {
    return res.status(403).json({ error: 'Access denied.' });
  }

  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.sendFile(resolvedPath);
});

// Sanitize original filename for display purposes only (never used for storage)
function sanitizeOriginalName(originalName) {
  if (!originalName) return 'unknown';
  // Remove path components and limit length
  const basename = path.basename(originalName);
  // Remove potentially dangerous characters
  const sanitized = basename.replace(/[^\w.\-\s]/g, '_').substring(0, 255);
  return sanitized || 'unknown';
}

// Global error handler
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);

  // Clean up uploaded file if there was an error
  if (req.file && req.file.path) {
    safeUnlink(req.file.path);
  }

  if (err.code === 'LIMIT_FILE_SIZE') {
    return res.status(413).json({ error: 'File size exceeds the allowed limit.' });
  }

  res.status(500).json({ error: 'Internal server error.' });
});

